import React from 'react';
import { Link } from 'react-router-dom';
import { Page } from '../components/Layout';

export default function AdminDashboard() {
  return (
    <Page title="Admin Dashboard" subtitle="Quick access to booking management screens.">
      <section className="grid cards3">
        <Link className="card adminShortcut" to="/admin/bookings">Manage Bookings</Link>
        <Link className="card adminShortcut" to="/admin/customers">Customers</Link>
        <Link className="card adminShortcut" to="/admin/variants">Variants</Link>
      </section>
    </Page>
  );
}
